/*
Design a time-based key-value data structure that can store multiple values for the same key at different time stamps and retrieve the latest key's value before a certain timestamp.

*/

```
    unordered_map<string, vector<pair<int,string>> > ump;

    void set(string key, string value, int timestamp) {
        ump[key].push_back({timestamp, value});
    }

    string get(string key, int timestamp) {
        auto it = upper_bound(ump[key].begin(), ump[key].end(), timestamp, [](const int &b, const pair<int, string> &a){ return b < a.first; });
        if(it == ump[key].begin()) return "";
        return (--it)->second;
    }
```

```
class Solution {
    static class TimeMap {
        private final Map<String, TreeMap<Integer, String>> keyValues;

        public TimeMap() {
            keyValues = new HashMap<>();
        }

        public void set(String key, String value, int timestamp) {
            keyValues.computeIfAbsent(key, k -> new TreeMap<>()).put(timestamp, value);
        }

        public String get(String key, int timestamp) {
            TreeMap<Integer, String> timestampValues = keyValues.get(key);

            if (timestampValues == null) {
                return "";
            }

            Integer floorTimestamp = timestampValues.floorKey(timestamp);

            return (floorTimestamp != null) ? timestampValues.get(floorTimestamp) : "";
        }
    }
```
